    53	static void handle_nr_rach(NR_UL_IND_t *UL_info)
    54	{
    55	  if (NFAPI_MODE == NFAPI_MODE_PNF) {
    56	    if (UL_info->rach_ind.number_of_pdus > 0) {
    57	      LOG_D(PHY,"UL_info->UL_info->rach_ind.number_of_pdus:%d SFN/Slot:%d.%d \n", UL_info->rach_ind.number_of_pdus, UL_info->rach_ind.sfn,UL_info->rach_ind.slot);
    58	      oai_nfapi_nr_rach_indication(&UL_info->rach_ind);
    59	      UL_info->rach_ind.number_of_pdus = 0;
    60	    }
    61	    return;
    62	  }
    63	  if (UL_info->rach_ind.number_of_pdus) {
    64	    LOG_D(MAC,
    65	          "UL_info[Frame %d, Slot %d] Calling initiate_ra_proc RACH:SFN/SLOT:%d/%d\n",
    66	          UL_info->frame,
    67	          UL_info->slot,
    68	          UL_info->rach_ind.sfn,
    69	          UL_info->rach_ind.slot);
    70	    for (int i = 0; i < UL_info->rach_ind.number_of_pdus; i++) {
    71	      nfapi_nr_prach_indication_pdu_t *rach = UL_info->rach_ind.pdu_list + i;
    72	      if (rach->num_preamble > 1) {
    73	        LOG_E(MAC, "Not more than 1 preamble per RACH PDU supported, ignoring the rest\n");
    74	      }
    75	      nr_initiate_ra_proc(UL_info->module_id,
    76	                          UL_info->CC_id,
    77	                          UL_info->rach_ind.sfn,
    78	                          UL_info->rach_ind.slot,
    79	                          rach->preamble_list[0].preamble_index,
    80	                          rach->freq_index,
    81	                          rach->symbol_index,
    82	                          rach->preamble_list[0].timing_advance,
    83	                          rach->preamble_list[0].preamble_pwr);
    84	    }
    85	  }
    86	}
