    88	static void handle_nr_uci(NR_UL_IND_t *UL_info)
    89	{
    90	  if(NFAPI_MODE == NFAPI_MODE_PNF) {
    91	    if (UL_info->uci_ind.num_ucis > 0) {
    92	      LOG_D(PHY,"PNF Sending UL_info->num_ucis:%d PDU_type: %d, SFN/SF:%d.%d \n", UL_info->uci_ind.num_ucis, UL_info->uci_ind.uci_list[0].pdu_type ,UL_info->frame, UL_info->slot);
    93	      oai_nfapi_nr_uci_indication(&UL_info->uci_ind);
    94	      UL_info->uci_ind.num_ucis = 0;
    95	    }
    96	    return;
    97	  }
    98	
    99	  const module_id_t mod_id = UL_info->module_id;
   100	  const frame_t frame = UL_info->uci_ind.sfn;
   101	  const slot_t slot = UL_info->uci_ind.slot;
   102	  int num_ucis = UL_info->uci_ind.num_ucis;
   103	  nfapi_nr_uci_t *uci_list = UL_info->uci_ind.uci_list;
   104	
   105	  for (int i = 0; i < num_ucis; i++) {
   106	    switch (uci_list[i].pdu_type) {
   107	      case NFAPI_NR_UCI_PUSCH_PDU_TYPE:
   108	        LOG_E(MAC, "%s(): unhandled NFAPI_NR_UCI_PUSCH_PDU_TYPE\n", __func__);
   109	        break;
   110	
   111	      case NFAPI_NR_UCI_FORMAT_0_1_PDU_TYPE: {
   112	        const nfapi_nr_uci_pucch_pdu_format_0_1_t *uci_pdu = &uci_list[i].pucch_pdu_format_0_1;
   113	        LOG_D(NR_MAC, "The received uci has sfn slot %d %d, num_ucis %d and pdu_size %d\n",
   114	                UL_info->uci_ind.sfn, UL_info->uci_ind.slot, num_ucis, uci_list[i].pdu_size);
   115	        handle_nr_uci_pucch_0_1(mod_id, frame, slot, uci_pdu);
   116	        break;
   117	      }
   118	
   119	        case NFAPI_NR_UCI_FORMAT_2_3_4_PDU_TYPE: {
   120	          const nfapi_nr_uci_pucch_pdu_format_2_3_4_t *uci_pdu = &uci_list[i].pucch_pdu_format_2_3_4;
   121	          handle_nr_uci_pucch_2_3_4(mod_id, frame, slot, uci_pdu);
   122	          break;
   123	        }
   124	      LOG_D(MAC, "UCI handled \n");
   125	    }
   126	  }
   127	
   128	  UL_info->uci_ind.num_ucis = 0;
