   136	static bool crc_sfn_slot_matcher(void *wanted, void *candidate)
   137	{
   138	  nfapi_nr_p7_message_header_t *msg = candidate;
   139	  struct sfn_slot *sfn_sf = (struct sfn_slot *)wanted;
   140	
   141	  switch (msg->message_id) {
   142	    case NFAPI_NR_PHY_MSG_TYPE_CRC_INDICATION: {
   143	      nfapi_nr_crc_indication_t *ind = candidate;
   144	      return sfn_sf->sfn == ind->sfn && sfn_sf->slot == ind->slot;
   145	    }
   146	
   147	    default:
   148	      LOG_E(NR_MAC, "sfn_slot_match bad ID: %d\n", msg->message_id);
   149	  }
   150	  return false;
   151	}
