   153	static void handle_nr_ulsch(NR_UL_IND_t *UL_info)
   154	{
   155	  if(NFAPI_MODE == NFAPI_MODE_PNF) {
   156	    if (UL_info->crc_ind.number_crcs > 0) {
   157	      LOG_D(PHY,"UL_info->UL_info->crc_ind.number_crcs:%d CRC_IND:SFN/Slot:%d.%d\n", UL_info->crc_ind.number_crcs, UL_info->crc_ind.sfn, UL_info->crc_ind.slot);
   158	      oai_nfapi_nr_crc_indication(&UL_info->crc_ind);
   159	      UL_info->crc_ind.number_crcs = 0;
   160	    }
   161	
   162	    if (UL_info->rx_ind.number_of_pdus > 0) {
   163	      LOG_D(PHY,"UL_info->rx_ind.number_of_pdus:%d RX_IND:SFN/Slot:%d.%d \n", UL_info->rx_ind.number_of_pdus, UL_info->rx_ind.sfn, UL_info->rx_ind.slot);
   164	      oai_nfapi_nr_rx_data_indication(&UL_info->rx_ind);
   165	      UL_info->rx_ind.number_of_pdus = 0;
   166	    }
   167	    return;
   168	  }
   169	
   170	  if (UL_info->rx_ind.number_of_pdus > 0 && UL_info->crc_ind.number_crcs > 0) {
   171	    AssertFatal(UL_info->rx_ind.number_of_pdus == UL_info->crc_ind.number_crcs,
   172	                "number_of_pdus %d, number_crcs %d\n",
   173	                UL_info->rx_ind.number_of_pdus, UL_info->crc_ind.number_crcs);
   174	    for (int i = 0; i < UL_info->rx_ind.number_of_pdus; i++) {
   175	      const nfapi_nr_rx_data_pdu_t *rx = &UL_info->rx_ind.pdu_list[i];
   176	      const nfapi_nr_crc_t *crc = &UL_info->crc_ind.crc_list[i];
   177	      LOG_D(NR_PHY, "UL_info->crc_ind.pdu_list[%d].rnti:%04x "
   178	                    "UL_info->rx_ind.pdu_list[%d].rnti:%04x\n",
   179	                    i, crc->rnti, i, rx->rnti);
   180	      AssertFatal(crc->rnti == rx->rnti, "mis-match between CRC RNTI %04x and RX RNTI %04x\n", crc->rnti, rx->rnti);
   181	
   182	      AssertFatal(crc->harq_id == rx->harq_id,
   183	                  "mis-match between CRC HARQ ID %04x and RX HARQ ID %04x\n",
   184	                  crc->harq_id,
   185	                  rx->harq_id);
   186	
   187	      LOG_D(NR_MAC,
   188	            "%4d.%2d Calling rx_sdu (CRC %s/tb_crc_status %d)\n",
   189	            UL_info->frame,
   190	            UL_info->slot,
   191	            crc->tb_crc_status ? "error" : "ok",
   192	            crc->tb_crc_status);
   193	
   194	      /* if CRC passes, pass PDU, otherwise pass NULL as error indication */
   195	      nr_rx_sdu(UL_info->module_id,
   196	                UL_info->CC_id,
   197	                UL_info->rx_ind.sfn,
   198	                UL_info->rx_ind.slot,
   199	                crc->rnti,
   200	                crc->tb_crc_status ? NULL : rx->pdu,
   201	                rx->pdu_length,
   202	                crc->harq_id,
   203	                crc->timing_advance,
   204	                crc->ul_cqi,
   205	                crc->rssi);
   206	    }
   207	    UL_info->rx_ind.number_of_pdus = 0;
   208	    UL_info->crc_ind.number_crcs = 0;
   209	  }
   210	}
