   275	static void remove_crc_pdu(nfapi_nr_crc_indication_t *crc_ind, int index) {
   276	  AssertFatal(index >= 0, "Invalid index %d\n", index);
   277	  AssertFatal(index < crc_ind->number_crcs, "Invalid index %d\n", index);
   278	  AssertFatal(crc_ind->number_crcs > 0, "Invalid crc_ind->number_crcs %d\n", crc_ind->number_crcs);
   279	
   280	  memmove(crc_ind->crc_list + index,
   281	          crc_ind->crc_list + index + 1,
   282	          sizeof(*crc_ind->crc_list) * (crc_ind->number_crcs - index - 1));
   283	  crc_ind->number_crcs--;
   284	}
