   286	static void remove_rx_pdu(nfapi_nr_rx_data_indication_t *rx_ind, int index) {
   287	  AssertFatal(index >= 0, "Invalid index %d\n", index);
   288	  AssertFatal(index < rx_ind->number_of_pdus, "Invalid index %d\n", index);
   289	  AssertFatal(rx_ind->number_of_pdus > 0, "Invalid rx_ind->number_of_pdus %d\n", rx_ind->number_of_pdus);
   290	
   291	  memmove(rx_ind->pdu_list + index,
   292	          rx_ind->pdu_list + index + 1,
   293	          sizeof(*rx_ind->pdu_list) * (rx_ind->number_of_pdus - index - 1));
   294	  rx_ind->number_of_pdus--;
