   306	static bool rx_ind_has_rnti(nfapi_nr_rx_data_indication_t *rx_ind, uint16_t rnti) {
   307	  for (int i = 0; i < rx_ind->number_of_pdus; i++) {
   308	    if (rnti == rx_ind->pdu_list[i].rnti) {
   309	      return true;
   310	    }
   311	  }
