   315	static void match_crc_rx_pdu(nfapi_nr_rx_data_indication_t *rx_ind, nfapi_nr_crc_indication_t *crc_ind) {
   316	  AssertFatal(crc_ind->number_crcs > 0 &&  rx_ind->number_of_pdus > 0,
   317	              "Invalid number of crc_ind->number_crcs %d or rx_ind->number_of_pdus %d\n",
   318	              crc_ind->number_crcs, rx_ind->number_of_pdus);
   319	  if (crc_ind->number_crcs > rx_ind->number_of_pdus) {
   320	    int num_unmatched_crcs = 0;
   321	    nfapi_nr_crc_indication_t *crc_ind_unmatched = calloc(1, sizeof(*crc_ind_unmatched));
   322	    crc_ind_unmatched->header = crc_ind->header;
   323	    crc_ind_unmatched->sfn = crc_ind->sfn;
   324	    crc_ind_unmatched->slot = crc_ind->slot;
   325	    crc_ind_unmatched->number_crcs = crc_ind->number_crcs - rx_ind->number_of_pdus;
   326	    crc_ind_unmatched->crc_list = calloc(crc_ind_unmatched->number_crcs, sizeof(nfapi_nr_crc_t));
   327	    for (int i = 0; i < crc_ind->number_crcs; i++) {
   328	      if (!rx_ind_has_rnti(rx_ind, crc_ind->crc_list[i].rnti)) {
   329	          LOG_I(NR_MAC, "crc_ind->crc_list[%d].rnti %x does not match any rx_ind pdu rnti\n",
   330	                i, crc_ind->crc_list[i].rnti);
   331	          crc_ind_unmatched->crc_list[num_unmatched_crcs] = crc_ind->crc_list[i];
   332	          num_unmatched_crcs++;
   333	          remove_crc_pdu(crc_ind, i);
   334	      }
   335	      if (crc_ind->number_crcs == rx_ind->number_of_pdus) {
   336	        break;
   337	      }
   338	    }
   339	    AssertFatal(crc_ind_unmatched->number_crcs == num_unmatched_crcs, "crc_ind num_pdus %d doesnt match %d\n",
   340	                crc_ind_unmatched->number_crcs, num_unmatched_crcs);
   341	    if (!requeue(&gnb_crc_ind_queue, crc_ind_unmatched))
   342	    {
   343	      LOG_E(NR_PHY, "requeue failed for crc_ind_unmatched.\n");
   344	      free_and_zero(crc_ind_unmatched->crc_list);
   345	      free_and_zero(crc_ind_unmatched);
   346	    }
   347	  }
   348	  else if (crc_ind->number_crcs < rx_ind->number_of_pdus) {
   349	    int num_unmatched_rxs = 0;
   350	    nfapi_nr_rx_data_indication_t *rx_ind_unmatched = calloc(1, sizeof(*rx_ind_unmatched));
   351	    rx_ind_unmatched->header = rx_ind->header;
   352	    rx_ind_unmatched->sfn = rx_ind->sfn;
   353	    rx_ind_unmatched->slot = rx_ind->slot;
   354	    rx_ind_unmatched->number_of_pdus = rx_ind->number_of_pdus - crc_ind->number_crcs;
   355	    rx_ind_unmatched->pdu_list = calloc(rx_ind_unmatched->number_of_pdus, sizeof(nfapi_nr_pdu_t));
   356	    for (int i = 0; i < rx_ind->number_of_pdus; i++) {
   357	      if (!crc_ind_has_rnti(crc_ind, rx_ind->pdu_list[i].rnti)) {
   358	        LOG_I(NR_MAC, "rx_ind->pdu_list[%d].rnti %x does not match any crc_ind pdu rnti\n", i, rx_ind->pdu_list[i].rnti);
   359	        rx_ind_unmatched->pdu_list[num_unmatched_rxs] = rx_ind->pdu_list[i];
   360	        num_unmatched_rxs++;
   361	        remove_rx_pdu(rx_ind, i);
   362	      }
   363	      if (rx_ind->number_of_pdus == crc_ind->number_crcs) {
   364	        break;
   365	      }
   366	    }
   367	    AssertFatal(rx_ind_unmatched->number_of_pdus == num_unmatched_rxs, "rx_ind num_pdus %d doesnt match %d\n",
   368	                rx_ind_unmatched->number_of_pdus, num_unmatched_rxs);
   369	    if (!requeue(&gnb_rx_ind_queue, rx_ind_unmatched))
   370	    {
   371	      LOG_E(NR_PHY, "requeue failed for rx_ind_unmatched.\n");
   372	      free_and_zero(rx_ind_unmatched->pdu_list);
   373	      free_and_zero(rx_ind_unmatched);
   374	    }
   375	  }
   376	  else {
   377	    LOG_E(NR_MAC, "The number of crc pdus %d = the number of rx pdus %d\n",
   378	          crc_ind->number_crcs, rx_ind->number_of_pdus);
   379	  }
   380	}
