   390	static void run_scheduler_monolithic(module_id_t module_id, int CC_id, int frame, int slot)
   391	{
   392	  NR_IF_Module_t *ifi = nr_if_inst[module_id];
   393	
   394	  LOG_D(NR_MAC, "Calling scheduler for %d.%d\n", frame, slot);
   395	  NR_Sched_Rsp_t *sched_info = allocate_sched_response();
   396	
   397	  // clear UL DCI prior to handling ULSCH
   398	  sched_info->UL_dci_req.numPdus = 0;
   399	  gNB_dlsch_ulsch_scheduler(module_id, frame, slot, sched_info);
   400	  ifi->CC_mask = 0;
   401	  sched_info->module_id = module_id;
   402	  sched_info->CC_id = CC_id;
   403	  sched_info->frame = frame;
