    22	/* sched response memory management */
    23	
    24	/* A system with reference counting is implemented.
    25	 * It is needed because several threads will access the structure,
    26	 * which has to be released only when all the threads are done with it.
    27	 * So the main thread allocates a sched_response with allocate_sched_response()
    28	 * which allocates a sched_response with a reference counter == 1
    29	 * and then for each other thread that will access sched_response, a
    30	 * call to inc_ref_sched_response() is done. When a thread has finished
    31	 * using the sched_response, it calls deref_sched_response() which will
    32	 * in turn call release_sched_response() when the reference counter becomes 0.
    33	 *
    34	 * The several threads in question are accessing the _same_ sched_response,
    35	 * it has not to be confused with the various TX processes that may run in
    36	 * parallel and which are accessing _different_ sched_response (the maximum
    37	 * number of parallel processes is N_RESP).
    38	 */
    39	
    40	#include "nr_sched_response.h"
    41	#include <pthread.h>
    42	#include <stdbool.h>
    43	#include <stdlib.h>
    44	#include "NR_PHY_INTERFACE/NR_IF_Module.h"
    45	#include "common/utils/LOG/log.h"
    46	#include "common/utils/assertions.h"
    47	
    48	#define N_RESP 3
    49	static NR_Sched_Rsp_t resp[N_RESP];
    50	static int resp_refcount[N_RESP];
    51	static int resp_freelist_next[N_RESP];
    52	static int resp_freelist_head;
    53	static pthread_mutex_t resp_mutex = PTHREAD_MUTEX_INITIALIZER;
    54	static bool resp_freelist_inited = false;
    55	
    56	void init_sched_response(void)
    57	{
    58	  /* init only once */
    59	  if (pthread_mutex_lock(&resp_mutex))
    60	    AssertFatal(0, "pthread_mutex_lock failed\n");
    61	  if (resp_freelist_inited) {
    62	    if (pthread_mutex_unlock(&resp_mutex))
    63	      AssertFatal(0, "pthread_mutex_unlock failed\n");
    64	    return;
    65	  }
    66	  resp_freelist_inited = true;
    67	  if (pthread_mutex_unlock(&resp_mutex))
    68	    AssertFatal(0, "pthread_mutex_unlock failed\n");
    69	
    70	  int i;
    71	  for (i = 0; i < N_RESP - 1; i++)
    72	    resp_freelist_next[i] = i + 1;
    73	  resp_freelist_next[N_RESP - 1] = -1;
    74	  resp_freelist_head = 0;
    75	}
    76	
    77	NR_Sched_Rsp_t *allocate_sched_response(void)
    78	{
    79	  NR_Sched_Rsp_t *ret;
    80	  int new_head;
    81	
    82	  if (pthread_mutex_lock(&resp_mutex))
    83	    AssertFatal(0, "pthread_mutex_lock failed\n");
    84	
    85	  AssertFatal(resp_freelist_inited, "sched_response used before init\n");
    86	
    87	  if (resp_freelist_head == -1) {
    88	    LOG_E(PHY, "fatal: sched_response cannot be allocated, increase N_RESP\n");
    89	    exit(1);
    90	  }
    91	
    92	  ret = &resp[resp_freelist_head];
    93	  ret->sched_response_id = resp_freelist_head;
    94	  resp_refcount[resp_freelist_head] = 1;
    95	
    96	  new_head = resp_freelist_next[resp_freelist_head];
    97	  resp_freelist_next[resp_freelist_head] = -1;
    98	  resp_freelist_head = new_head;
    99	
   100	  if (pthread_mutex_unlock(&resp_mutex))
   101	    AssertFatal(0, "pthread_mutex_unlock failed\n");
   102	
   103	  return ret;
   104	}
   105	
   106	static void release_sched_response(int sched_response_id)
   107	{
   108	  LOG_D(NR_MAC,"Releasing sched_response %d\n",sched_response_id);      
   109	  resp_freelist_next[sched_response_id] = resp_freelist_head;
   110	  resp_freelist_head = sched_response_id;
   111	}
   112	
   113	void deref_sched_response(int sched_response_id)
   114	{
   115	  /* simulators (ulsim/dlsim) deal with their own sched_response but call
   116	   * functions that call this one, let's handle this case with a special
   117	   * value -1 where we do nothing (yes it's a hack)
   118	   */
   119	  if (sched_response_id == -1)
   120	    return;
   121	
   122	  if (pthread_mutex_lock(&resp_mutex))
   123	    AssertFatal(0, "pthread_mutex_lock failed\n");
   124	
   125	  AssertFatal(resp_freelist_inited, "sched_response used before init\n");
   126	  AssertFatal(resp_refcount[sched_response_id] > 0, "sched_reponse decreased too much\n");
   127	
   128	  LOG_D(NR_MAC,"resp_refcount[%d] %d\n",sched_response_id,resp_refcount[sched_response_id]);
   129	  resp_refcount[sched_response_id]--;
   130	  if (resp_refcount[sched_response_id] == 0)
   131	    release_sched_response(sched_response_id);
   132	
   133	  if (pthread_mutex_unlock(&resp_mutex))
   134	    AssertFatal(0, "pthread_mutex_unlock failed\n");
   135	}
   136	
   137	void inc_ref_sched_response(int sched_response_id)
   138	{
   139	  /* simulators (ulsim/dlsim) deal with their own sched_response but call
   140	   * functions that call this one, let's handle this case with a special
   141	   * value -1 where we do nothing (yes it's a hack)
   142	   */
   143	  if (sched_response_id == -1)
   144	    return;
   145	
   146	  LOG_D(NR_MAC,"Incrementing sched_resp resp_refounct[%d] = %d\n",
   147	                  sched_response_id,resp_refcount[sched_response_id]);
   148	  if (pthread_mutex_lock(&resp_mutex))
   149	    AssertFatal(0, "pthread_mutex_lock failed\n");
   150	
   151	  AssertFatal(resp_freelist_inited, "sched_response used before init\n");
   152	
   153	  resp_refcount[sched_response_id]++;
   154	
   155	  if (pthread_mutex_unlock(&resp_mutex))
   156	    AssertFatal(0, "pthread_mutex_unlock failed\n");
   157	}
